# @cctt_verify {"v":2,"sym":"sympy.printing.tests.test_rust.test_user_functions","kind":"function","src_hash":"c2166758277f7453","in":{"base":"Any"},"out":{"base":"Any","pred":"rust_code(ceiling(x), user_functions=custom_functions) == 'x.ceil()' and rust_code(Abs(x), user_functions=custom_functions) == 'fabs(x)' and rust_code(Abs(n), user_functions=custom_functions) == 'abs(n)'"},"spec":{"lhs":"test_user_functions()","rhs":"test_user_functions produces the expected output","over":{"base":"Any"},"name":"test_user_functions_correct"},"guarantee":"test_user_functions produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.printing.tests.test_rust.test_user_functions_correct","statement":"Path(test_user_functions(x), test_user_functions produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ebda9c4ab24f2b21"}
def test_user_functions():
    x = symbols('x', integer=False)
    n = symbols('n', integer=True)
    custom_functions = {
        "ceiling": "ceil",
        "Abs": [(lambda x: not x.is_integer, "fabs", 4), (lambda x: x.is_integer, "abs", 4)],
    }
    assert rust_code(ceiling(x), user_functions=custom_functions) == "x.ceil()"
    assert rust_code(Abs(x), user_functions=custom_functions) == "fabs(x)"
    assert rust_code(Abs(n), user_functions=custom_functions) == "abs(n)"


